export enum Language {
  ENGLISH = 'English',
  HINDI = 'Hindi',
  MARATHI = 'Marathi',
  TAMIL = 'Tamil',
  TELUGU = 'Telugu',
  BENGALI = 'Bengali',
  KANNADA = 'Kannada',
  MALAYALAM = 'Malayalam',
  GUJARATI = 'Gujarati',
  PUNJABI = 'Punjabi'
}

export interface Script {
  id: string;
  title: string;
  content: string;
  language: Language;
  createdAt: number;
}

export interface BrandVisual {
  id: string;
  prompt: string;
  url: string;
  createdAt: number;
}

export interface Project {
  id: string;
  name: string;
  scripts: Script[];
  visuals: BrandVisual[];
}

import { GoogleGenAI } from "@google/genai";

export const generateVisual = async (prompt: string): Promise<string | null> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // Using gemini-2.5-flash-image for generation
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `Create a high-quality, professional marketing visual for an Indian brand. The visual should be culturally relevant and visually striking. Prompt: ${prompt}`,
          },
        ],
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini Image Generation Error:", error);
    return null;
  }
};

import { Language } from '../types';

const OPENROUTER_API_KEY = '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';

export const generateScript = async (
  brandName: string,
  productDescription: string,
  targetAudience: string,
  language: Language
): Promise<string | null> => {
  try {
    const prompt = `
      Act as a high-end Indian ad agency scriptwriter. 
      Brand: ${brandName}
      Product: ${productDescription}
      Audience: ${targetAudience}
      Language: ${language}

      Generate a 30-second creative ad script that is culturally resonant with ${language}-speaking regions in India. 
      Include:
      1. Scene descriptions
      2. Dialogue/Voiceover
      3. Background music/SFX suggestions

      The tone should be professional yet emotive.
    `;

    const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${OPENROUTER_API_KEY}`,
        "HTTP-Referer": window.location.origin,
        "X-Title": "BharatAI Studio",
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        "model": "google/gemini-2.0-flash-exp:free",
        "messages": [
          { "role": "user", "content": prompt }
        ]
      })
    });

    const data = await response.json();
    return data.choices[0]?.message?.content || null;
  } catch (error) {
    console.error("OpenRouter Script Generation Error:", error);
    return null;
  }
};

import React, { useState } from 'react';
import { generateScript } from '../services/openRouterService';
import { Language } from '../types';
import { Send, Copy, Check, Download, Languages } from 'lucide-react';

const ScriptGenerator: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [brandName, setBrandName] = useState('');
  const [productDesc, setProductDesc] = useState('');
  const [audience, setAudience] = useState('');
  const [language, setLanguage] = useState<Language>(Language.HINDI);
  const [result, setResult] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleGenerate = async () => {
    if (!brandName || !productDesc) return;
    setLoading(true);
    const script = await generateScript(brandName, productDesc, audience, language);
    setResult(script);
    setLoading(false);
    // Save to history (localStorage mock)
    const history = JSON.parse(localStorage.getItem('bharat_scripts') || '[]');
    history.unshift({
      id: Date.now().toString(),
      title: `${brandName} Ad`,
      content: script,
      language,
      createdAt: Date.now()
    });
    localStorage.setItem('bharat_scripts', JSON.stringify(history.slice(0, 20)));
  };

  const copyToClipboard = () => {
    if (result) {
      navigator.clipboard.writeText(result);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="grid lg:grid-cols-2 gap-8">
      <div className="space-y-6">
        <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-2 mb-6">
            <div className="w-1.5 h-6 bg-orange-600 rounded-full" />
            <h2 className="text-xl font-bold">Script Architect</h2>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Brand Name</label>
              <input 
                type="text"
                placeholder="e.g. Tanishq, Amul, Zomato"
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all"
                value={brandName}
                onChange={(e) => setBrandName(e.target.value)}
              />
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-1">Product Description</label>
              <textarea 
                placeholder="What are we selling? Describe the product's uniqueness..."
                rows={3}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all"
                value={productDesc}
                onChange={(e) => setProductDesc(e.target.value)}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Target Audience</label>
                <input 
                  type="text"
                  placeholder="e.g. Gen Z, Moms"
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all"
                  value={audience}
                  onChange={(e) => setAudience(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Primary Language</label>
                <select 
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all bg-white"
                  value={language}
                  onChange={(e) => setLanguage(e.target.value as Language)}
                >
                  {Object.values(Language).map(lang => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
              </div>
            </div>

            <button 
              onClick={handleGenerate}
              disabled={loading || !brandName || !productDesc}
              className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-slate-800 disabled:opacity-50 transition-all shadow-lg"
            >
              {loading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <><Send size={18} /> Generate Script</>
              )}
            </button>
          </div>
        </div>
      </div>

      <div className="flex flex-col">
        {result ? (
          <div className="bg-slate-900 text-slate-100 p-8 rounded-2xl shadow-xl flex-1 relative overflow-hidden group">
            <div className="absolute top-4 right-4 flex gap-2">
              <button 
                onClick={copyToClipboard}
                className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-300"
                title="Copy to clipboard"
              >
                {copied ? <Check size={18} className="text-green-400" /> : <Copy size={18} />}
              </button>
              <button className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors text-slate-300">
                <Download size={18} />
              </button>
            </div>

            <div className="mb-6 flex items-center gap-2">
              <Languages size={16} className="text-orange-400" />
              <span className="text-xs uppercase tracking-widest font-bold text-slate-400">{language} Engine Output</span>
            </div>

            <div className="prose prose-invert max-w-none prose-p:leading-relaxed whitespace-pre-wrap">
              {result}
            </div>
          </div>
        ) : (
          <div className="flex-1 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center text-slate-400 p-8 text-center bg-white/50">
            <PenTool size={48} className="mb-4 opacity-20" />
            <h3 className="font-semibold text-slate-500 mb-2">No Script Generated Yet</h3>
            <p className="text-sm max-w-xs">Fill in your brand details to generate a culturally relevant advertising script.</p>
