import { GoogleGenAI } from "@google/genai";
import { Language } from '../types';

/**
 * Generates an advertising script using the Gemini API.
 * This function has been refactored to use the @google/genai SDK directly.
 */
export const generateScript = async (
  brandName: string,
  productDescription: string,
  targetAudience: string,
  language: Language
): Promise<string | null> => {
  try {
    // Initialize the Gemini AI client using the provided environment variable.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      Act as a high-end Indian ad agency scriptwriter. 
      Brand: ${brandName}
      Product: ${productDescription}
      Audience: ${targetAudience}
      Language: ${language}

      Generate a 30-second creative ad script that is culturally resonant with ${language}-speaking regions in India. 
      Include:
      1. Scene descriptions
      2. Dialogue/Voiceover
      3. Background music/SFX suggestions

      The tone should be professional yet emotive.
    `;

    // Using 'gemini-3-flash-preview' for basic creative text generation tasks.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    // Extracting the text content directly using the .text property from the response object.
    return response.text || null;
  } catch (error) {
    console.error("Gemini Script Generation Error:", error);
    return null;
  }
};

