import React, { useState, useRef } from 'react';
import { generateScript } from '../services/openRouterService';
import { generateAudio, pcmToWav } from '../services/geminiService';
import { saveProjectData } from '../services/supabaseClient';
import { Language } from '../types';
import { 
  Send, 
  Copy, 
  Check, 
  Download, 
  Languages, 
  PenTool, 
  Volume2, 
  Play, 
  Pause,
  CloudUpload,
  // Fix: Import missing Zap icon
  Zap
} from 'lucide-react';

const ScriptGenerator: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [audioLoading, setAudioLoading] = useState(false);
  const [brandName, setBrandName] = useState('');
  const [productDesc, setProductDesc] = useState('');
  const [audience, setAudience] = useState('');
  const [language, setLanguage] = useState<Language>(Language.HINDI);
  const [result, setResult] = useState<string | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const handleGenerate = async () => {
    if (!brandName || !productDesc) return;
    setLoading(true);
    setAudioUrl(null);
    const script = await generateScript(brandName, productDesc, audience, language);
    setResult(script);
    setLoading(false);

    // Save to Supabase (and Local Storage)
    await saveProjectData('script', { brandName, script, language });

    const history = JSON.parse(localStorage.getItem('bharat_scripts') || '[]');
    history.unshift({
      id: Date.now().toString(),
      title: `${brandName} Ad`,
      content: script,
      language,
      createdAt: Date.now()
    });
    localStorage.setItem('bharat_scripts', JSON.stringify(history.slice(0, 20)));
  };

  const handleGenerateAudio = async () => {
    if (!result) return;
    setAudioLoading(true);
    const audioData = await generateAudio(result, language);
    if (audioData) {
      const wavUrl = pcmToWav(audioData);
      setAudioUrl(wavUrl);
      await saveProjectData('audio', { brandName, audioUrl: wavUrl });
    }
    setAudioLoading(false);
  };

  const downloadScript = () => {
    if (!result) return;
    const element = document.createElement("a");
    const file = new Blob([result], {type: 'text/plain'});
    element.href = URL.createObjectURL(file);
    element.download = `${brandName}_script.txt`;
    document.body.appendChild(element);
    element.click();
  };

  const copyToClipboard = () => {
    if (result) {
      navigator.clipboard.writeText(result);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="grid lg:grid-cols-2 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="space-y-6">
        <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-sm border dark:border-slate-800">
          <div className="flex items-center gap-2 mb-6">
            <div className="w-2 h-8 bg-brand-primary rounded-full" />
            <h2 className="text-2xl font-bold tracking-tight">Script Engine</h2>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Brand Identity</label>
              <input 
                type="text"
                placeholder="e.g. AIVISION Premium"
                className="w-full px-4 py-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none focus:ring-2 focus:ring-brand-primary outline-none transition-all dark:text-white"
                value={brandName}
                onChange={(e) => setBrandName(e.target.value)}
              />
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Creative Brief</label>
              <textarea 
                placeholder="Describe your goals, product features, and key messaging..."
                rows={4}
                className="w-full px-4 py-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none focus:ring-2 focus:ring-brand-primary outline-none transition-all dark:text-white"
                value={productDesc}
                onChange={(e) => setProductDesc(e.target.value)}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Demographics</label>
                <input 
                  type="text"
                  placeholder="e.g. Urban Youth"
                  className="w-full px-4 py-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none focus:ring-2 focus:ring-brand-primary outline-none transition-all dark:text-white"
                  value={audience}
                  onChange={(e) => setAudience(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Dialect</label>
                <select 
                  className="w-full px-4 py-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none focus:ring-2 focus:ring-brand-primary outline-none transition-all dark:text-white"
                  value={language}
                  onChange={(e) => setLanguage(e.target.value as Language)}
                >
                  {Object.values(Language).map(lang => (
                    <option key={lang} value={lang}>{lang}</option>
                  ))}
                </select>
              </div>
            </div>

            <button 
              onClick={handleGenerate}
              disabled={loading || !brandName || !productDesc}
              className="w-full bg-brand-primary text-white py-5 rounded-2xl font-extrabold flex items-center justify-center gap-2 hover:bg-orange-600 disabled:opacity-50 transition-all shadow-xl shadow-brand-primary/20 active:scale-[0.98]"
            >
              {loading ? (
                <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <><Send size={20} /> Generate Narrative</>
              )}
            </button>
          </div>
        </div>
      </div>

      <div className="flex flex-col gap-6">
        {result ? (
          <div className="bg-slate-900 dark:bg-slate-900 text-slate-100 p-8 rounded-3xl shadow-2xl flex-1 relative overflow-hidden flex flex-col">
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-2">
                <div className="p-2 bg-brand-primary/10 rounded-lg">
                  <PenTool size={18} className="text-brand-primary" />
                </div>
                <span className="text-xs uppercase tracking-[0.2em] font-bold text-slate-400">Campaign Output</span>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={copyToClipboard}
                  className="p-3 bg-slate-800 hover:bg-slate-700 rounded-xl transition-all text-slate-300"
                  title="Copy"
                >
                  {copied ? <Check size={18} className="text-green-400" /> : <Copy size={18} />}
                </button>
                <button 
                  onClick={downloadScript}
                  className="p-3 bg-slate-800 hover:bg-slate-700 rounded-xl transition-all text-slate-300"
                  title="Download Script"
                >
                  <Download size={18} />
                </button>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
              <div className="prose prose-invert max-w-none whitespace-pre-wrap text-slate-300 leading-relaxed text-lg">
                {result}
              </div>
            </div>

            <div className="mt-8 pt-6 border-t border-slate-800">
               {audioUrl ? (
                 <div className="flex flex-col gap-4">
                    <div className="flex items-center justify-between">
                       <span className="text-xs font-bold text-slate-500 flex items-center gap-2 uppercase tracking-widest"><Volume2 size={14}/> Audio Asset Ready</span>
                       <a href={audioUrl} download={`${brandName}_audio.wav`} className="text-brand-primary hover:underline text-xs font-bold flex items-center gap-1">
                          <Download size={14}/> Download Audio
                       </a>
                    </div>
                    <audio ref={audioRef} src={audioUrl} controls className="w-full h-10 filter invert brightness-200" />
                 </div>
               ) : (
                 <button 
                    onClick={handleGenerateAudio}
                    disabled={audioLoading}
                    className="w-full py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl flex items-center justify-center gap-3 transition-all text-sm font-bold text-slate-200 border border-slate-700"
                 >
                   {audioLoading ? (
                     <div className="w-5 h-5 border-2 border-brand-primary/30 border-t-brand-primary rounded-full animate-spin" />
                   ) : (
                     <><Volume2 size={18} className="text-brand-primary"/> Generate Professional Voiceover</>
                   )}
                 </button>
               )}
            </div>
          </div>
        ) : (
          <div className="flex-1 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-3xl flex flex-col items-center justify-center text-slate-400 p-8 text-center bg-white/30 dark:bg-slate-900/30 backdrop-blur-sm">
            <div className="w-20 h-20 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mb-6">
              <Zap size={40} className="opacity-10 text-brand-primary" />
            </div>
            <h3 className="font-bold text-slate-600 dark:text-slate-300 mb-2 text-xl">Awaiting Intelligence</h3>
            <p className="text-sm max-w-xs text-slate-500">Submit your brief to AIVISION's neural core to generate culturally synchronized scripts and audio.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ScriptGenerator;

