import { GoogleGenAI, Type } from "@google/genai";
import { Language, Mood, Region } from '../types';

/**
 * Generates multiple advertising script variations using the Gemini API.
 */
export const generateScript = async (
  brandName: string,
  productDescription: string,
  targetAudience: string,
  language: Language,
  mood: Mood,
  region: Region
): Promise<string[] | null> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const prompt = `
      Act as a world-class Indian ad agency scriptwriter. 
      Brand: ${brandName}
      Product: ${productDescription}
      Audience: ${targetAudience}
      Language: ${language}
      Mood/Tone: ${mood}
      Region: ${region}

      Generate THREE distinct 30-second creative ad script variations that are culturally tailored for the ${region} region and reflect a ${mood} mood. 
      The scripts must be in ${language}.

      Each script should include:
      1. Scene descriptions (Visuals)
      2. Dialogue/Voiceover (Audio)
      3. Background music & SFX suggestions

      Ensure the narrative feels authentic to local values and colloquialisms of ${region}.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            variations: {
              type: Type.ARRAY,
              items: {
                type: Type.STRING,
                description: "Full ad script text including scene descriptions and dialogue."
              },
              minItems: 3,
              maxItems: 3
            }
          },
          required: ["variations"]
        }
      }
    });

    const parsed = JSON.parse(response.text);
    return parsed.variations || null;
  } catch (error) {
    console.error("Gemini Script Generation Error:", error);
    return null;
  }
};

