/**
 * Saves project artifacts to Supabase if configured, otherwise falls back to local storage.
 */
export const saveProjectData = async (type: 'script' | 'visual' | 'audio', data: any) => {
  if (!isSupabaseConfigured) {
    console.warn("Supabase not configured. Saving project locally.");
    return;
  }

  try {
    const { error } = await supabase
      .from('projects')
      .insert([{ 
        type, 
        content: data, 
        created_at: new Date().toISOString() 
      }]);

    if (error) {
      if (error.code === 'PGRST116') {
        console.warn(`Supabase: Table 'projects' not found. Data not persisted to database.`);
      } else {
        throw error;
      }
    }
  } catch (e) {
    console.debug("AIVISION Storage: Supabase error.", e);
  }
};

