const ProjectHistory: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [items, setItems] = useState<any[]>([]);
  const [filter, setFilter] = useState<'all' | 'script' | 'visual'>('all');

  useEffect(() => {
    fetchHistory();
  }, []);

  const fetchHistory = async () => {
    setLoading(true);
    try {
      // 1. Try fetching from Supabase
      const { data, error } = await supabase
        .from('projects')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      setItems(data || []);
    } catch (err) {
      console.warn("Supabase Fetch Failed, falling back to Local Storage");
      // 2. Local Fallback
      const scripts = JSON.parse(localStorage.getItem('bharat_scripts') || '[]').map((s: any) => ({ ...s, type: 'script' }));
      const visuals = JSON.parse(localStorage.getItem('bharat_visuals') || '[]').map((v: any) => ({ ...v, type: 'visual' }));
      setItems([...scripts, ...visuals].sort((a, b) => b.createdAt - a.createdAt));
    } finally {
      setLoading(false);
    }
  };

  const deleteItem = async (id: string, type: string) => {
    if (!confirm("Are you sure you want to delete this asset from the archive?")) return;

    try {
      await supabase.from('projects').delete().eq('id', id);
      setItems(prev => prev.filter(item => item.id !== id));
    } catch (e) {
      // Local delete logic
      const storageKey = type === 'script' ? 'bharat_scripts' : 'bharat_visuals';
      const history = JSON.parse(localStorage.getItem(storageKey) || '[]');
      const updated = history.filter((h: any) => h.id !== id);
      localStorage.setItem(storageKey, JSON.stringify(updated));
      setItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const filteredItems = items.filter(item => filter === 'all' || item.type === filter);

  if (loading) return (
    <div className="h-96 flex flex-col items-center justify-center gap-4">
      <Loader2 className="animate-spin text-brand-primary" size={40} />
      <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Accessing Neural Archive...</p>
    </div>
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-extrabold tracking-tighter flex items-center gap-3">
            <Cloud className="text-brand-primary" size={32} />
            Asset Library
          </h2>
          <p className="text-slate-500 text-sm font-medium mt-1">Unified cloud storage for your regional creative variations.</p>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex bg-slate-100 dark:bg-slate-900 p-1 rounded-2xl border dark:border-slate-800">
            <button onClick={() => setFilter('all')} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${filter === 'all' ? 'bg-white dark:bg-slate-800 shadow-sm text-brand-primary' : 'text-slate-500'}`}>All</button>
            <button onClick={() => setFilter('script')} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${filter === 'script' ? 'bg-white dark:bg-slate-800 shadow-sm text-brand-primary' : 'text-slate-500'}`}>Scripts</button>
            <button onClick={() => setFilter('visual')} className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${filter === 'visual' ? 'bg-white dark:bg-slate-800 shadow-sm text-brand-primary' : 'text-slate-500'}`}>Visuals</button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredItems.map((item) => (
          <div key={item.id} className="group bg-white dark:bg-slate-900 rounded-[2rem] border dark:border-slate-800 shadow-sm hover:shadow-2xl hover:-translate-y-1 transition-all overflow-hidden relative">

            {item.type === 'visual' && item.content?.imageUrl && (
              <div className="aspect-video relative overflow-hidden">
                <img src={item.content.imageUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt="" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent flex items-end p-6">
                   <div className="flex items-center gap-2 text-white/70 text-[10px] font-bold uppercase tracking-widest">
                      <ImageIcon size={14} /> Synthetic Asset
                   </div>
                </div>
              </div>
            )}

            <div className="p-8">
              <div className="flex items-center justify-between mb-4">
                <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${item.type === 'script' ? 'bg-brand-primary/10 text-brand-primary' : 'bg-blue-500/10 text-blue-500'}`}>
                   {item.type === 'script' ? 'Script Variation' : 'Visual Concept'}
                </span>
                <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1">
                  <Calendar size={12} /> {new Date(item.created_at).toLocaleDateString()}
                </span>
              </div>

              <h4 className="font-extrabold text-lg mb-3 line-clamp-1">
                {item.type === 'script' ? (item.content?.brandName || 'Unnamed Brand') : (item.content?.prompt || 'Generated Concept')}
              </h4>

              <p className="text-slate-500 dark:text-slate-400 text-sm line-clamp-3 mb-6 font-medium leading-relaxed italic">
                {item.type === 'script' ? item.content?.scripts?.[0] : `Atmospheric generation for ${item.content?.mood || 'Professional'} intent.`}
              </p>

              <div className="flex items-center justify-between pt-6 border-t dark:border-slate-800">
                <div className="flex items-center gap-2">
                   <div className="w-6 h-6 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-[10px] font-black text-brand-primary">
                      {item.content?.language?.[0] || 'IN'}
                   </div>
                   <span className="text-[10px] font-bold text-slate-400">{item.content?.region || 'Global'}</span>
                </div>
                <div className="flex gap-2">
                   <button onClick={() => deleteItem(item.id, item.type)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 rounded-lg transition-all" title="Delete Permanent">
