const Auth: React.FC<{ onAuth: () => void }> = ({ onAuth }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [loading, setLoading] = useState(false);
  const [resending, setResending] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [needsVerification, setNeedsVerification] = useState(false);

  // Clear states when toggling between Sign In and Sign Up
  useEffect(() => {
    setError(null);
    setSuccessMsg(null);
    setNeedsVerification(false);
  }, [isSignUp]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMsg(null);
    setNeedsVerification(false);

    try {
      if (isSignUp) {
        const { error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: fullName }
          }
        });
        if (error) throw error;
        setSuccessMsg('Identity created. Please check your inbox to verify your account.');
      } else {
        const { error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) {
          // Detect "Email not confirmed" specifically
          if (error.message?.toLowerCase().includes('email not confirmed')) {
            setNeedsVerification(true);
          }
          throw error;
        }
        onAuth();
      }
