import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Zap, Mail, Lock, User, ArrowRight, Loader2, AlertCircle, ShieldAlert, CheckCircle2, RefreshCw, KeyRound, ArrowLeft } from 'lucide-react';

const Auth: React.FC<{ onAuth: () => void }> = ({ onAuth }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [otp, setOtp] = useState('');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<'credentials' | 'otp'>('credentials');
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  // Reset states when switching between Sign In and Sign Up
  useEffect(() => {
    setError(null);
    setSuccessMsg(null);
    setStep('credentials');
    setOtp('');
  }, [isSignUp]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMsg(null);

    try {
      if (isSignUp) {
        const { data, error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: fullName }
          }
        });
        if (error) throw error;

        // If user already exists but unconfirmed, or just created
        setStep('otp');
        setSuccessMsg('Verification code sent to your email.');
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });

        if (error) {
          if (error.message?.toLowerCase().includes('email not confirmed')) {
            // Trigger a resend to ensure they have a fresh OTP
            await supabase.auth.resend({ type: 'signup', email });
            setStep('otp');
            setError('Please verify your email to continue. We just sent a fresh code.');
          } else {
            throw error;
          }
        } else if (data.session) {
          onAuth();
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      setError(err.message || 'Authentication failed. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const { data, error } = await supabase.auth.verifyOtp({
        email,
        token: otp,
        type: 'signup' // This works for both initial signup and confirming an existing unconfirmed user
      });

      if (error) throw error;

      if (data.session) {
        setSuccessMsg('Identity verified successfully!');
        setTimeout(() => onAuth(), 1000);
      }
    } catch (err: any) {
      setError(err.message || 'Invalid or expired OTP code.');
    } finally {
      setLoading(false);
    }
  };

  const handleResendOtp = async () => {
    setLoading(true);
    setError(null);
    try {
      const { error } = await supabase.auth.resend({
        type: 'signup',
        email: email,
      });
      if (error) throw error;
      setSuccessMsg('A fresh 6-digit code has been dispatched.');
    } catch (err: any) {
      setError(err.message || 'Wait a moment before requesting another code.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-slate-950">
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-brand-primary/10 rounded-full blur-[120px] animate-pulse" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-brand-secondary/10 rounded-full blur-[120px] animate-pulse-slow" />
      </div>

      <div className="w-full max-w-md bg-white/5 backdrop-blur-xl border border-white/10 p-10 rounded-[2.5rem] shadow-2xl relative z-10 animate-in fade-in zoom-in-95 duration-500">
        <div className="flex flex-col items-center mb-10 text-center">
          <div className="bg-brand-primary p-4 rounded-2xl shadow-lg mb-6 group hover:scale-110 transition-transform">
            <Zap className="text-white w-8 h-8" />
          </div>
          <h1 className="text-3xl font-extrabold text-white tracking-tighter mb-2">
            AIVISION <span className="text-brand-primary">Studio</span>
          </h1>
          <p className="text-slate-400 text-sm font-medium">Regional Creative Intelligence Engine</p>
          <div className="mt-4 px-3 py-1 bg-white/5 rounded-full border border-white/10 flex items-center gap-2">
            <div className="w-1.5 h-1.5 rounded-full bg-green-500" />
            <code className="text-[10px] text-slate-500 uppercase tracking-tighter">OTP Auth Protocol Active</code>
          </div>
        </div>

        {step === 'credentials' ? (
          <form onSubmit={handleAuth} className="space-y-4">
            {isSignUp && (
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                <input
                  type="text"
                  placeholder="Full Name"
                  required
                  className="w-full pl-12 pr-4 py-4 rounded-xl bg-white/5 border border-white/10 focus:border-brand-primary focus:ring-1 focus:ring-brand-primary text-white transition-all outline-none"
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                />
              </div>
            )}

            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input
                type="email"
                placeholder="Email Address"
                required
                className="w-full pl-12 pr-4 py-4 rounded-xl bg-white/5 border border-white/10 focus:border-brand-primary focus:ring-1 focus:ring-brand-primary text-white transition-all outline-none"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>

            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input
                type="password"
                placeholder="Password"
                required
                className="w-full pl-12 pr-4 py-4 rounded-xl bg-white/5 border border-white/10 focus:border-brand-primary focus:ring-1 focus:ring-brand-primary text-white transition-all outline-none"
