  useEffect(() => {
    if (resendCooldown > 0) {
      const timer = setTimeout(() => setResendCooldown(resendCooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [resendCooldown]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMsg(null);

    try {
      if (isSignUp) {
        const { data, error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: fullName }
          }
        });
        if (error) throw error;

        setStep('otp');
        setSuccessMsg('A 6-digit verification code was dispatched to your inbox.');
        setResendCooldown(60);
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });

        if (error) {
          if (error.message?.toLowerCase().includes('email not confirmed')) {
            // Trigger a resend to get a fresh OTP
            const { error: resendErr } = await supabase.auth.resend({ type: 'signup', email });
            if (resendErr) throw resendErr;

            setStep('otp');
            setError('Account exists but email is unverified. We just sent a fresh code.');
            setResendCooldown(60);
          } else {
            throw error;
          }
        } else if (data.session) {
          onAuth();
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      let errMsg = err.message || 'Authentication failed.';

      // Specific handling for Rate Limits
      if (errMsg.toLowerCase().includes('rate limit exceeded')) {
        errMsg = "Security block: Too many email requests. Please wait a few minutes or use Demo Mode below.";
        setShowTroubleshoot(true);
      }

      setError(errMsg);
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const { data, error } = await supabase.auth.verifyOtp({
        email,
        token: otp,
        type: 'signup'
      });

      if (error) throw error;

      if (data.session) {
        setSuccessMsg('Neural identity verified. Synchronizing...');
        setTimeout(() => onAuth(), 1000);
      }
    } catch (err: any) {
      setError(err.message || 'Invalid or expired OTP code.');
    } finally {
      setLoading(false);
    }
  };

  const handleResendOtp = async () => {
    if (resendCooldown > 0) return;

    setLoading(true);
    setError(null);
    try {
      const { error } = await supabase.auth.resend({
        type: 'signup',
        email: email,
      });
      if (error) throw error;
      setSuccessMsg('A fresh verification code has been generated.');
      setResendCooldown(60);
    } catch (err: any) {
      let errMsg = err.message || 'Failed to resend code.';
      if (errMsg.toLowerCase().includes('rate limit exceeded')) {
        errMsg = "Email rate limit exceeded. Supabase allows 1 email per minute. Try Demo Mode.";
        setShowTroubleshoot(true);
      }
      setError(errMsg);
    } finally {
      setLoading(false);
    }
  };

  const handleDemoMode = () => {
    localStorage.setItem('aivision_demo_mode', 'true');
    onAuth();
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-slate-950">
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-brand-primary/10 rounded-full blur-[120px] animate-pulse" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-brand-secondary/10 rounded-full blur-[120px] animate-pulse-slow" />
      </div>

      <div className="w-full max-w-md bg-white/5 backdrop-blur-xl border border-white/10 p-10 rounded-[2.5rem] shadow-2xl relative z-10 animate-in fade-in zoom-in-95 duration-500">
        <div className="flex flex-col items-center mb-10 text-center">
          <div className="bg-brand-primary p-4 rounded-2xl shadow-lg mb-6 group hover:scale-110 transition-transform">
            <Zap className="text-white w-8 h-8" />
          </div>
          <h1 className="text-3xl font-extrabold text-white tracking-tighter mb-2">
            AIVISION <span className="text-brand-primary">Studio</span>
          </h1>
          <p className="text-slate-400 text-sm font-medium italic">Advanced Multimodal Creative Suite</p>
          <div className="mt-4 px-3 py-1 bg-white/5 rounded-full border border-white/10 flex items-center gap-2">
            <div className="w-1.5 h-1.5 rounded-full bg-green-500" />
            <code className="text-[10px] text-slate-500 uppercase tracking-tighter">Rate Limit Protection: Enabled</code>
          </div>
        </div>

        {step === 'credentials' ? (
          <form onSubmit={handleAuth} className="space-y-4">
            {isSignUp && (
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                <input
                  type="text"
                  placeholder="Full Name"
                  required
                  className="w-full pl-12 pr-4 py-4 rounded-xl bg-white/5 border border-white/10 focus:border-brand-primary focus:ring-1 focus:ring-brand-primary text-white transition-all outline-none"
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                />
              </div>
            )}

            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input
                type="email"
                placeholder="Email Address"
                required
                className="w-full pl-12 pr-4 py-4 rounded-xl bg-white/5 border border-white/10 focus:border-brand-primary focus:ring-1 focus:ring-brand-primary text-white transition-all outline-none"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>

            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input
                type="password"
                placeholder="Password"
                required
                className="w-full pl-12 pr-4 py-4 rounded-xl bg-white/5 border border-white/10 focus:border-brand-primary focus:ring-1 focus:ring-brand-primary text-white transition-all outline-none"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
            </div>

            {error && (
              <div className="flex flex-col gap-3 p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-xs font-bold animate-in shake duration-300">
                <div className="flex items-start gap-2">
                  <AlertCircle size={14} className="mt-0.5 shrink-0" />
                  <p className="leading-tight">{error}</p>
                </div>
              </div>
            )}

            <button
              disabled={loading}
              className="w-full bg-brand-primary hover:bg-orange-600 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95 mt-6 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin" size={20} /> : <>{isSignUp ? 'Create Account' : 'Sign In'} <ArrowRight size={18} /></>}
            </button>
          </form>
        ) : (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <div className="text-center space-y-2">
              <h3 className="text-white font-bold text-lg">Verify Your Identity</h3>
              <p className="text-slate-400 text-xs px-4 leading-relaxed">
                Enter the 6-digit code sent to <br/><span className="text-brand-primary font-bold">{email}</span>
              </p>
            </div>

            <form onSubmit={handleVerifyOtp} className="space-y-4">
              <div className="relative">
                <KeyRound className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                <input
                  type="text"
                  maxLength={6}
                  placeholder="000000"
                  required
                  autoFocus
                  className="w-full pl-12 pr-4 py-5 rounded-xl bg-white/5 border border-white/10 focus:border-brand-primary focus:ring-1 focus:ring-brand-primary text-white text-2xl tracking-[0.5em] font-mono text-center outline-none"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value.replace(/\D/g, ''))}
                />
              </div>

              {error && (
                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-xs font-bold">
                  <div className="flex items-start gap-2">
                    <AlertCircle size={14} className="mt-0.5 shrink-0" />
                    <p>{error}</p>
                  </div>
                </div>
              )}

              {successMsg && (
                <div className="p-4 bg-green-500/10 border border-green-500/20 rounded-xl text-green-400 text-xs font-bold">
                  <div className="flex items-start gap-2">
                    <CheckCircle2 size={14} className="mt-0.5 shrink-0" />
                    <p>{successMsg}</p>
                  </div>
                </div>
              )}

              <button
                disabled={loading || otp.length !== 6}
                className="w-full bg-brand-primary hover:bg-orange-600 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95 disabled:opacity-50"
              >
                {loading ? <Loader2 className="animate-spin" size={20} /> : 'Finalize Verification'}
              </button>
            </form>

            <div className="pt-4 border-t border-white/5 space-y-4">
              <button
                onClick={handleResendOtp}
                disabled={loading || resendCooldown > 0}
                className={`w-full py-2 text-xs font-bold flex items-center justify-center gap-2 transition-colors ${resendCooldown > 0 ? 'text-slate-600 cursor-not-allowed' : 'text-slate-400 hover:text-white'}`}
              >
                {resendCooldown > 0 ? (
                  <><Timer size={14} /> Resend in {resendCooldown}s</>
                ) : (
                  <><RefreshCw size={14} /> Resend OTP Code</>
                )}
              </button>

              <button 
                onClick={() => setShowTroubleshoot(!showTroubleshoot)}
                className="w-full flex items-center justify-center gap-2 text-[10px] text-brand-primary font-black uppercase tracking-widest hover:underline"
              >
                <HelpCircle size={12} /> Email issue or Rate Limit?
              </button>

              {showTroubleshoot && (
                <div className="p-5 bg-white/5 rounded-2xl border border-white/10 space-y-4 animate-in fade-in slide-in-from-top-2">
                  <div className="flex items-start gap-3">
                    <ShieldAlert size={14} className="text-brand-secondary shrink-0 mt-0.5" />
                    <p className="text-[11px] text-slate-400 leading-relaxed italic">
                      Supabase limits emails to 1 per minute. If you hit a <b>Rate Limit</b>, wait 60 seconds or use the bypass below for your project demo.
                    </p>
                  </div>
                  <button 
                    onClick={handleDemoMode}
                    className="w-full py-3 bg-brand-secondary/20 hover:bg-brand-secondary/30 text-brand-secondary border border-brand-secondary/30 rounded-xl text-[10px] font-bold uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-inner"
                  >
                    <Zap size={12} className="fill-brand-secondary" /> Emergency Demo Bypass
                  </button>
                </div>
              )}

              <button
                onClick={() => setStep('credentials')}
                className="w-full py-2 text-slate-600 hover:text-slate-400 text-[10px] uppercase font-bold tracking-widest flex items-center justify-center gap-1 transition-colors"
              >
                <ArrowLeft size={12} /> Change Credentials
              </button>
            </div>
          </div>
        )}

        {step === 'credentials' && (
          <div className="mt-8 text-center flex flex-col gap-4">
            <button
              onClick={() => setIsSignUp(!isSignUp)}
              className="text-slate-400 hover:text-white text-sm font-bold transition-colors"
            >
              {isSignUp ? 'Already have an account? Sign In' : "Don't have an account? Sign Up"}
            </button>

            {error?.includes('Rate Limit') && (
              <button 
                onClick={handleDemoMode}
                className="px-6 py-3 bg-white/5 border border-brand-primary/20 rounded-xl text-[10px] text-brand-primary font-bold uppercase tracking-[0.2em] transition-all hover:bg-brand-primary/10 flex items-center justify-center gap-2"
              >
                <Zap size={12} /> Immediate Demo Access
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Auth;

