import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Zap, Mail, Lock, User, ArrowRight, Loader2, 
  AlertCircle, ShieldAlert, CheckCircle2, RefreshCw, 
  KeyRound, ArrowLeft, Info, ExternalLink, HelpCircle,
  Timer
} from 'lucide-react';

const Auth: React.FC<{ onAuth: () => void }> = ({ onAuth }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [otp, setOtp] = useState('');
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<'credentials' | 'otp'>('credentials');
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [showTroubleshoot, setShowTroubleshoot] = useState(false);
  const [resendCooldown, setResendCooldown] = useState(0);

  useEffect(() => {
    setError(null);
    setSuccessMsg(null);
    setStep('credentials');
    setOtp('');
  }, [isSignUp]);

  // Handle Resend Cooldown Timer
  useEffect(() => {
    if (resendCooldown > 0) {
      const timer = setTimeout(() => setResendCooldown(resendCooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [resendCooldown]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMsg(null);

    try {
      if (isSignUp) {
        const { data, error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: fullName }
          }
        });
        if (error) throw error;

        setStep('otp');
        setSuccessMsg('A 6-digit verification code was dispatched to your inbox.');
        setResendCooldown(60);
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });

        if (error) {
          if (error.message?.toLowerCase().includes('email not confirmed')) {
            // Trigger a resend to get a fresh OTP
            const { error: resendErr } = await supabase.auth.resend({ type: 'signup', email });
            if (resendErr) throw resendErr;

            setStep('otp');
            setError('Account exists but email is unverified. We just sent a fresh code.');
            setResendCooldown(60);
          } else {
            throw error;
          }
        } else if (data.session) {
          onAuth();
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      let errMsg = err.message || 'Authentication failed.';

      // Specific handling for Rate Limits
      if (errMsg.toLowerCase().includes('rate limit exceeded')) {
        errMsg = "Security block: Too many email requests. Please wait a few minutes or use Demo Mode below for your presentation.";
        setShowTroubleshoot(true);
      }

      setError(errMsg);
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
