To set up your database for **AIVISION Studio**, copy and run the following SQL script in the **SQL Editor** of your Supabase Dashboard. This script creates the necessary tables, sets up security (RLS), and includes a **trigger** that automatically creates a user profile whenever someone signs up.

```sql
-- 1. Create a table for Public Profiles (Syncs with Auth)
create table public.profiles (
  id uuid references auth.users on delete cascade not null primary key,
  full_name text,
  avatar_url text,
  company_name text,
  updated_at timestamp with time zone,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 2. Create a table for AI Projects (Scripts, Visuals, Audio)
create table public.projects (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references auth.users on delete cascade not null,
  type text not null check (type in ('script', 'visual', 'audio')),
  content jsonb not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 3. Enable Row Level Security (RLS)
-- This ensures users can only access their own data
alter table public.profiles enable row level security;
alter table public.projects enable row level security;

-- 4. Create Security Policies
create policy "Profiles are viewable by everyone" on profiles
  for select using (true);

create policy "Users can update their own profile" on profiles
  for update using (auth.uid() = id);

create policy "Users can view their own projects" on projects
  for select using (auth.uid() = user_id);

create policy "Users can create their own projects" on projects
  for insert with check (auth.uid() = user_id);

create policy "Users can delete their own projects" on projects
  for delete using (auth.uid() = user_id);

-- 5. Create a Trigger for Automatic Profile Creation
-- This function runs every time a new user signs up
create function public.handle_new_user()
returns trigger as $$
begin
  insert into public.profiles (id, full_name, avatar_url)
  values (new.id, new.raw_user_meta_data->>'full_name', new.raw_user_meta_data->>'avatar_url');
  return new;
end;
$$ language plpgsql security definer;

-- Apply the trigger to the auth.users table
create trigger on_auth_user_created
  after insert on auth.users
  for each row execute procedure public.handle_new_user();
```

I have also updated the **Admin Dashboard** in the application to include this improved SQL script for your reference.

