} from 'lucide-react';

interface AdminUser {
  id: string;
  email: string;
  full_name: string;
  avatar_url: string;
  created_at: string;
  company_name?: string;
}

const AdminDashboard: React.FC = () => {
  const [users, setUsers] = useState<AdminUser[]>([]);
  const [projectsCount, setProjectsCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'users' | 'setup'>('users');
  const [copied, setCopied] = useState(false);

  const sqlCode = `-- 1. RESET AND INITIALIZE DATABASE (ADMIN OVERRIDE)
-- Use these commands to ensure you can see ALL data without security restrictions.

-- Drop existing policies if they block data visibility
drop policy if exists "Profiles are viewable by everyone" on public.profiles;
drop policy if exists "Users can view their own projects" on public.projects;

-- ENABLE GLOBAL READ ACCESS (NO SECURITY)
-- This allows you to see all users and projects in the dashboard.
alter table public.profiles disable row level security;
alter table public.projects disable row level security;

-- 2. CREATE TABLES (IF NOT ALREADY CREATED)
create table if not exists public.profiles (
  id uuid primary key,
  full_name text,
  avatar_url text,
  company_name text,
  updated_at timestamp with time zone,
  created_at timestamp with time zone default now()
);

create table if not exists public.projects (
  id uuid default gen_random_uuid() primary key,
  user_id uuid,
  type text,
  content jsonb,
  created_at timestamp with time zone default now()
);`;

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      // Fetch all profiles from the public profiles table
      const { data: profilesData, error: profilesError } = await supabase
        .from('profiles')
        .select('*')
        .order('created_at', { ascending: false });

      if (profilesError) throw profilesError;
      setUsers(profilesData || []);

      // Fetch all projects count
      const { count, error: projectsError } = await supabase
        .from('projects')
        .select('*', { count: 'exact', head: true });

      if (!projectsError) setProjectsCount(count || 0);

    } catch (err: any) {
      console.error("Admin Fetch Error:", err);
      setError("Database connection established, but tables might be restricted or empty. Use 'SQL Setup' to disable RLS.");
    } finally {
      setLoading(false);
    }
  };

  const copySql = () => {
    navigator.clipboard.writeText(sqlCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const filteredUsers = users.filter(u => 
    u.email?.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.full_name?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
