const OPENROUTER_API_KEY = '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';

/**
 * Generates multiple advertising script variations using the OpenRouter API.
 * Implements a fallback mechanism across several free models to ensure high availability.
 */
export const generateScript = async (
  brandName: string,
  productDescription: string,
  targetAudience: string,
  language: Language,
  mood: Mood,
  region: Region
): Promise<string[] | null> => {
  // Array of free models to try in sequence if one fails
  const models = [
    "google/gemini-2.0-flash-lite-preview-02-05:free",
    "google/gemini-2.0-pro-exp-02-05:free",
    "mistralai/pixtral-12b:free",
    "meta-llama/llama-3.3-70b-instruct:free"
  ];

  for (const model of models) {
    try {
      console.debug(`Attempting script generation with model: ${model}`);

      const prompt = `
        Act as a world-class Indian ad agency scriptwriter. 
        Brand: ${brandName}
        Product: ${productDescription}
        Audience: ${targetAudience}
        Language: ${language}
        Mood/Tone: ${mood}
        Region: ${region}

        Generate THREE distinct 30-second creative ad script variations that are culturally tailored for the ${region} region and reflect a ${mood} mood. 
        The scripts must be in ${language}.

        Each script should include:
        1. Scene descriptions (Visuals)
        2. Dialogue/Voiceover (Audio)
        3. Background music & SFX suggestions

        IMPORTANT: Your response must be strictly valid JSON. 
        JSON structure: {"variations": ["Full script text 1", "Full script text 2", "Full script text 3"]}
        Do not include any preamble, markdown code blocks, or postscript.
      `;

      const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${OPENROUTER_API_KEY}`,
          "Content-Type": "application/json",
          "HTTP-Referer": window.location.origin,
          "X-Title": "AIVISION Studio"
        },
        body: JSON.stringify({
          "model": model,
          "messages": [
            { "role": "system", "content": "You are a specialized ad scriptwriting assistant that outputs only valid JSON objects." },
            { "role": "user", "content": prompt }
          ],
          "response_format": { "type": "json_object" }
        })
      });

      if (!response.ok) {
        const errorText = await response.text();
        console.warn(`OpenRouter API Error (${model}): Status ${response.status} - ${errorText}`);
        continue; // Try the next model in the list
      }

      const data = await response.json();
      const content = data.choices[0]?.message?.content;

      if (!content) {
        console.warn(`Empty content received from model: ${model}`);
        continue;
      }

      try {
        // Clean the content if it contains markdown code blocks
        const cleanedContent = content.replace(/```json/g, '').replace(/```/g, '').trim();
        const parsed = JSON.parse(cleanedContent);

        if (parsed.variations && Array.isArray(parsed.variations)) {
          console.info(`Successfully generated variations using ${model}`);
          return parsed.variations;
        } else {
          console.warn(`Invalid JSON structure from ${model}:`, parsed);
        }
      } catch (parseError) {
        console.error(`JSON Parse Error for model ${model}:`, content);
      }

    } catch (error) {
      console.error(`Network or Execution Error with model ${model}:`, error);
    }
  }

  console.error("Critical failure: All available OpenRouter models failed to generate a valid response.");
  return null;
};

