      if (!response.ok) {
        const errorText = await response.text();
        console.warn(`[OpenRouter] ${model} failed (Status ${response.status}): ${errorText}`);
        continue;
      }

      const data = await response.json();
      const content = data.choices?.[0]?.message?.content;

      if (!content) {
        console.warn(`[OpenRouter] ${model} returned empty content.`);
        continue;
      }

      try {
        // Robust extraction: find the first '{' and last '}' to isolate JSON from potential model chatter
        const jsonMatch = content.match(/\{[\s\S]*\}/);
        const jsonString = jsonMatch ? jsonMatch[0] : content;
        const parsed = JSON.parse(jsonString);

        if (parsed.variations && Array.isArray(parsed.variations)) {
          console.info(`[OpenRouter] Success with model: ${model}`);
          return parsed.variations;
        } else {
          console.warn(`[OpenRouter] ${model} returned invalid JSON structure:`, parsed);
        }
      } catch (parseError) {
        console.error(`[OpenRouter] JSON Parse Failure (${model}):`, content);
      }

    } catch (error) {
      console.error(`[OpenRouter] Network error with ${model}:`, error);
    }
  }

  console.error("Critical failure: All OpenRouter free models exhausted. Check API key status or network connectivity.");
  return null;
};

