/**
 * Generates multiple advertising script variations.
 * Tries OpenRouter free models first, then falls back to Gemini 3 Flash if needed.
 */
export const generateScript = async (
  brandName: string,
  productDescription: string,
  targetAudience: string,
  language: Language,
  mood: Mood,
  region: Region
): Promise<string[] | null> => {
  const models = [
    "google/gemini-2.0-flash-lite-preview-02-05:free",
    "deepseek/deepseek-r1:free",
    "mistralai/mistral-7b-instruct:free",
    "meta-llama/llama-3-8b-instruct:free"
  ];

  const prompt = `
    Act as a world-class Indian ad agency scriptwriter. 
    Brand: ${brandName}
    Product: ${productDescription}
    Audience: ${targetAudience}
    Language: ${language}
    Mood/Tone: ${mood}
    Region: ${region}

    Generate THREE distinct 30-second creative ad script variations tailored for the ${region} region. 
    The scripts must be in ${language} and reflect a ${mood} mood.

    Each script should include visual scene descriptions and audio dialogue.

    OUTPUT FORMAT: You must return a JSON object with exactly this structure:
    {"variations": ["Script 1", "Script 2", "Script 3"]}

    Return ONLY the JSON. No preamble.
  `;

  // Try OpenRouter models
  for (const model of models) {
    try {
      console.debug(`[AIVISION] Attempting OpenRouter model: ${model}`);
      const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${OPENROUTER_API_KEY}`,
          "Content-Type": "application/json",
          "HTTP-Referer": window.location.origin,
          "X-Title": "AIVISION Studio"
        },
        body: JSON.stringify({
          "model": model,
          "messages": [{ "role": "user", "content": prompt }],
          "temperature": 0.7
        })
      });

      if (response.ok) {
        const data = await response.json();
        const content = data.choices?.[0]?.message?.content;
        if (content) {
          const jsonMatch = content.match(/\{[\s\S]*\}/);
          const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : content);
          if (parsed.variations) return parsed.variations;
        }
      }
    } catch (e) {
      console.warn(`[AIVISION] OpenRouter ${model} failed, trying next...`);
    }
  }

  // Final Fallback: Use Gemini 3 Flash directly
  console.info("[AIVISION] OpenRouter exhausted. Failing over to Gemini 3 Flash...");
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const result = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json"
      }
    });
    const parsed = JSON.parse(result.text);
    return parsed.variations || null;
  } catch (geminiError) {
    console.error("[AIVISION] All script generation paths failed.", geminiError);
    return null;
  }
};

import { GoogleGenAI } from "@google/genai";
import { Region } from '../types';

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface MarketInsight {
  trend: string;
  relevance: string;
  sources: { title: string; uri: string }[];
}

/**
 * Fetches real-time market trends for specific Indian regions using Google Search Grounding.
 * Uses gemini-3-pro-image-preview as required for search tool access.
 */
export const fetchMarketTrends = async (region: Region, industry: string = "Consumer Goods"): Promise<MarketInsight | null> => {
  try {
    const ai = getAI();
    const prompt = `What are the current trending creative themes, visual styles, and consumer behaviors for ${industry} advertising specifically in ${region} region of India? Focus on news from the last 30 days and regional cultural nuances.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-image-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "No insights found.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const sources = chunks
      .filter((chunk: any) => chunk.web)
      .map((chunk: any) => ({
        title: chunk.web.title,
        uri: chunk.web.uri
      }));

    return {
      trend: text,
      relevance: `Grounded Regional Intelligence for ${region}`,
      sources: sources
    };
  } catch (error) {
    console.error("Market Trend Fetch Error:", error);
    throw error; // Rethrow to handle in UI
  }
};

