                AIVISION
              </h1>
            </div>

            <nav className="flex-1 p-4 space-y-2 mt-4">
              <SidebarLink to="/" icon={<LayoutDashboard size={18} />} label="Overview" />
              <SidebarLink to="/scripts" icon={<PenTool size={18} />} label="Script Engine" />
              <SidebarLink to="/visuals" icon={<ImageIcon size={18} />} label="Visual Studio" />
              <SidebarLink to="/video" icon={<Clapperboard size={18} />} label="Cinema Studio" />
              <SidebarLink to="/history" icon={<History size={18} />} label="Archive" />
              <SidebarLink to="/profile" icon={<UserIcon size={18} />} label="Identity" />

              {isAdmin && (
                <div className="pt-4 mt-4 border-t border-slate-200 dark:border-slate-800">
