const ProjectHistory: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [items, setItems] = useState<any[]>([]);
  const [filter, setFilter] = useState<'all' | 'script' | 'visual' | 'audio'>('all');

  useEffect(() => {
    fetchHistory();
  }, []);

  const fetchHistory = async () => {
    setLoading(true);
    try {
      // 1. Try fetching from Supabase
      const { data, error } = await supabase
        .from('projects')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      setItems(data || []);
    } catch (err) {
      console.warn("Supabase Fetch Failed, falling back to Local Storage");
      // 2. Local Fallback aggregation
      const scripts = JSON.parse(localStorage.getItem('bharat_scripts') || '[]').map((s: any) => ({ ...s, type: 'script' }));
      const visuals = JSON.parse(localStorage.getItem('bharat_visuals') || '[]').map((v: any) => ({ ...v, type: 'visual' }));
      const audio = JSON.parse(localStorage.getItem('bharat_audio') || '[]').map((a: any) => ({ ...a, type: 'audio' }));

      const allItems = [...scripts, ...visuals, ...audio].sort((a, b) => {
        const dateA = new Date(a.created_at || a.createdAt).getTime();
        const dateB = new Date(b.created_at || b.createdAt).getTime();
        return dateB - dateA;
      });
      setItems(allItems);
    } finally {
      setLoading(false);
    }
  };

  const deleteItem = async (id: string, type: string) => {
    if (!confirm("Are you sure you want to delete this asset from the archive?")) return;

    try {
      const { error } = await supabase.from('projects').delete().eq('id', id);
      if (error) throw error;
      setItems(prev => prev.filter(item => item.id !== id));
    } catch (e) {
      // Local delete fallback
      const storageKeys: Record<string, string> = {
        'script': 'bharat_scripts',
        'visual': 'bharat_visuals',
        'audio': 'bharat_audio'
      };
      const key = storageKeys[type];
      if (key) {
        const history = JSON.parse(localStorage.getItem(key) || '[]');
        const updated = history.filter((h: any) => h.id !== id);
        localStorage.setItem(key, JSON.stringify(updated));
      }
      setItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const filteredItems = items.filter(item => filter === 'all' || item.type === filter);

  const renderAudioPlayer = (audioBase64: string) => {
    const url = pcmToWav(audioBase64);
    return (
      <div className="mt-4 p-3 bg-slate-100 dark:bg-slate-800 rounded-xl flex items-center gap-3">
        <audio src={url} controls className="w-full h-8 brightness-90 opacity-80" />
      </div>
    );
  };

  if (loading) return (
    <div className="h-96 flex flex-col items-center justify-center gap-4">
      <Loader2 className="animate-spin text-brand-primary" size={40} />
      <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Accessing Neural Archive...</p>
    </div>
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-extrabold tracking-tighter flex items-center gap-3">
            <Cloud className="text-brand-primary" size={32} />
            Asset Library
          </h2>
          <p className="text-slate-500 text-sm font-medium mt-1">Unified cloud storage for your regional creative variations.</p>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex bg-slate-100 dark:bg-slate-900 p-1 rounded-2xl border dark:border-slate-800 overflow-x-auto no-scrollbar">
            <button onClick={() => setFilter('all')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${filter === 'all' ? 'bg-white dark:bg-slate-800 shadow-sm text-brand-primary' : 'text-slate-500'}`}>All</button>
            <button onClick={() => setFilter('script')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${filter === 'script' ? 'bg-white dark:bg-slate-800 shadow-sm text-brand-primary' : 'text-slate-500'}`}>Scripts</button>
            <button onClick={() => setFilter('visual')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${filter === 'visual' ? 'bg-white dark:bg-slate-800 shadow-sm text-brand-primary' : 'text-slate-500'}`}>Visuals</button>
            <button onClick={() => setFilter('audio')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${filter === 'audio' ? 'bg-white dark:bg-slate-800 shadow-sm text-brand-primary' : 'text-slate-500'}`}>Audio</button>
