      contents: [{ parts: [{ text: `Act as a professional Indian voiceover artist. Read this script in ${language} with high emotional resonance and perfect regional accent: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
